fun main() {
    // A tiny unnamed function stored inside a variable!
    val printGreeting = { println("Hello from the Lambda!") }

    // We trigger the logic by calling the variable with ()
    printGreeting()
}

fun main() {
    // Takes a String parameter named 'name'
    val sayHello = { name: String -> 
        println("Hello, $name!") 
    }

    sayHello("Alice")
    sayHello("Bob")
}
